### 3. 重写 `create_demo` 函数中的 UI 布局部分

请替换原有的 `create_demo` 函数内容。此次修改：
1.  调整了左侧 Dataset 表格的布局，删除了复杂的表头，增加了 Add/Delete 按钮。
2.  调整了右侧 Plan 和 Code 的 `gr.Row` 参数（`equal_height=False`）以实现顶端对齐。
3.  添加了必要的事件绑定逻辑。

```python
def create_demo() -> gr.Blocks:
    global _DEMO_THEME, _DEMO_CSS
    # 1. 配置主题和 CSS (保持不变)
    theme = gr.themes.Soft(
        primary_hue="emerald",
        neutral_hue="slate",
        radius_size="md",
        text_size="sm",
        font=[gr.themes.GoogleFont("Inter"), "sans-serif"],
        font_mono=[gr.themes.GoogleFont("JetBrains Mono"), "monospace"],
    )
    _DEMO_THEME = theme
    _DEMO_CSS = _CUSTOM_CSS

    # 2. 准备默认数据 (保持不变)
    default_sample = DEFAULT_SAMPLE
    default_task = default_sample.get("task", {})
    default_benchmark = default_task.get("benchmark", {})
    default_dataset_rows: List[List[str]] = []
    if default_sample.get("datasets"):
        default_dataset_rows = [[d.get("dataset_id", "")] for d in default_sample["datasets"] if d.get("dataset_id")]

    # 3. 辅助 HTML 函数 (保持不变)
    def get_header_html():
        return f"""
        <div style="display: flex; align-items: center; gap: 16px;">
            <img src="{LOGO_SRC}" style="height: 48px; width: auto; border-radius: 8px;" alt="Logo" />
            <div>
                <h1 style="font-size: 1.5rem; font-weight: 800; color: #0f172a; margin: 0; letter-spacing: -0.02em;">DataChef</h1>
                <div style="font-size: 0.875rem; color: #64748b; font-weight: 500;">
                    Automatic Data Recipe Generation for LLM Adaptation
                </div>
            </div>
        </div>
        """
    def get_status_text():
        model_id = _resolve_model_id()
        if _use_remote_llm():
            status_dot = "<span style='width: 8px; height: 8px; background: #10b981; border-radius: 50%; display: inline-block;'></span>"
            status_text = f"<span style='color: #059669; font-weight: 600;'>Ready</span>"
            model_info = f"<span style='color: #475569;'><b>{model_id}</b></span>"
        else:
            status_dot = "<span style='width: 8px; height: 8px; background: #f59e0b; border-radius: 50%; display: inline-block;'></span>"
            status_text = f"<span style='color: #d97706; font-weight: 600;'>Not Configured</span>"
            model_info = "<span style='color: #475569;'>Remote vLLM unset</span>"
        return f"<div style='display: flex; align-items: center; justify-content: space-between; width: 100%;'><div style='display: flex; align-items: center; gap: 8px;'>{status_dot} {status_text}</div><div style='font-size: 0.8rem;'>{model_info}</div></div>"

    # 4. 构建 UI
    with gr.Blocks(title="DataChef", theme=theme, css=_DEMO_CSS) as demo:
        # --- 顶部 Header ---
        with gr.Row(elem_classes=["header-container"]):
            gr.HTML(get_header_html())

        # --- 主体布局 ---
        with gr.Row():
            # =============== 左侧控制面板 (Left Column) ===============
            with gr.Column(scale=32, elem_classes=["control-panel"]):
                # 顶部状态栏
                with gr.Row(elem_classes=["status-bar-compact"]):
                    status_html = gr.HTML(get_status_text())
                    load_model_btn = gr.Button("↻", size="sm", variant="secondary", min_width=30)

                # 预设选择
                gr.HTML("<div class='green-header'>📋 Configuration Presets</div>")
                preset_dropdown = gr.Dropdown(choices=list(PRESETS.keys()), value="Physics", show_label=False, container=False, interactive=True)

                # 任务描述
                gr.HTML("<div class='green-header'>🎯 Task Description</div>")
                task_description = gr.Textbox(show_label=False, lines=3, value=default_task.get("description", ""), placeholder="Describe task...", elem_classes=["no-label-input"])

                # Benchmark 设置
                gr.HTML("<div class='green-header'>⚖️ Benchmark Settings</div>")
                with gr.Group():
                    benchmark_name = gr.Textbox(label="Name", placeholder="Name", value=default_benchmark.get("name", ""), lines=1)
                    benchmark_description = gr.Textbox(label="Description", placeholder="Description (optional)", lines=3, value=default_benchmark.get("description", ""))

                # 数据集选择 (优化后)
                gr.HTML("<div class='green-header'>📚 Raw Dataset Sources</div>")

                # 1. Suggested 部分
                with gr.Row(elem_classes=["mb-2"]):
                    gr.HTML("<div style='font-size: 0.85rem; font-weight: 600; color: #64748b; display:flex; align-items:center;'>🔍 Suggested</div>")
                    auto_ds_btn = gr.Button("Auto Search", variant="secondary", size="sm", scale=0)

                suggested_ds = gr.Dataframe(
                    headers=["Dataset ID"],  # 简化表头
                    datatype=["str"],
                    row_count=(3, "fixed"),
                    value=[],
                    interactive=False,
                    wrap=True,
                    elem_classes=["dataframe-compact"]
                )

                # 添加按钮 (Suggested -> Selected)
                with gr.Row():
                    add_suggested_btn = gr.Button("⬇️ Add Suggested", variant="secondary", size="sm")

                # 2. Selected 部分
                gr.HTML("<div style='font-size: 0.85rem; font-weight: 600; color: #64748b; margin-top: 12px;'>✅ Selected</div>")

                dataset_ids = gr.Dataframe(
                    headers=["Dataset ID"], # 简化表头，不需要 huggingface dataset id 那么长
                    datatype=["str"],
                    row_count=(3, "dynamic"),
                    value=default_dataset_rows,
                    interactive=True,
                    col_count=(1, "fixed"),
                    wrap=True
                )

                # Dataset 操作按钮 (-Delete, +Add)
                selected_ds_idx = gr.State(value=None)
                with gr.Row(elem_classes=["btn-row", "mt-2"]):
                    del_row_btn = gr.Button("- Delete", variant="stop", size="sm")
                    add_row_btn = gr.Button("+ Add", variant="secondary", size="sm")

                # 状态存储
                suggested_selected_idx = gr.State(value=None)

                # 运行按钮
                with gr.Row(elem_classes=["mt-4"]):
                    run_btn = gr.Button("🚀 Generate Recipe", variant="primary", size="lg")

            # =============== 右侧输出面板 (Right Column) ===============
            with gr.Column(scale=68):
                # 进度状态
                process_status = gr.HTML(visible=False, label=None)

                # Plan & Code 分栏视图
                # 修改：equal_height=False 配合 CSS 的 flex-start，让内容从顶部开始对齐
                with gr.Row(equal_height=False, elem_classes=["mt-0"]):
                    # Plan
                    with gr.Column(variant="panel", elem_classes=["output-panel"]):
                        gr.HTML("<div class='green-header'>🧠 Processing Plan</div>")
                        with gr.Tabs():
                            with gr.Tab("Rendered"):
                                plan_out_md = gr.Markdown(value="_Waiting..._", line_breaks=True)
                            with gr.Tab("Source"):
                                plan_out_raw = gr.Code(language="markdown", interactive=False, lines=15, elem_classes=["code-box"])

                    # Code
                    with gr.Column(variant="panel", elem_classes=["output-panel"]):
                        gr.HTML("<div class='green-header'>💻 Executable Code</div>")
                        code_out = gr.Code(language="python", interactive=False, lines=18, elem_classes=["code-box"])

                # 结果面板
                with gr.Column(variant="panel", elem_classes=["output-panel", "mt-4"]):
                    gr.HTML("<div class='green-header'>📊 Data Inspector & Results</div>")
                    with gr.Tabs():
                        with gr.Tab("🏆 Processed Training Data"):
                            eval_output_html = gr.HTML("Recipe generation not started yet.", elem_classes=["data-table-host"])
                        with gr.Tab("📥 Raw Data Preview"):
                            preview_out_html = gr.HTML("Waiting for input...", elem_classes=["data-table-host"])

        # --- 事件绑定 ---
        preset_dropdown.change(
            fn=_load_preset_config,
            inputs=[preset_dropdown],
            outputs=[task_description, benchmark_name, benchmark_description, dataset_ids]
        )

        # 自动搜索
        auto_ds_btn.click(
            fn=_auto_suggest_datasets_ui,
            inputs=[task_description, benchmark_description],
            outputs=[suggested_ds, suggested_selected_idx],
        )

        # 选中 Suggested 行
        suggested_ds.select(
            _on_df_select,
            outputs=[suggested_selected_idx],
        )

        # 将 Suggested 添加到 Selected
        add_suggested_btn.click(
            fn=_add_selected_suggestion,
            inputs=[dataset_ids, suggested_ds, suggested_selected_idx],
            outputs=[dataset_ids],
        )

        # 选中 Selected 行 (用于删除)
        dataset_ids.select(
            _on_df_select,
            outputs=[selected_ds_idx]
        )

        # 删除 Selected 行
        del_row_btn.click(
            fn=_delete_selected_row,
            inputs=[dataset_ids, selected_ds_idx],
            outputs=[dataset_ids, selected_ds_idx] # 删除后重置选中状态
        )

        # 添加空行到 Selected
        add_row_btn.click(
            fn=_add_empty_row,
            inputs=[dataset_ids],
            outputs=[dataset_ids]
        )

        # 运行逻辑
        run_btn.click(
            _run_full_automation,
            inputs=[task_description, benchmark_name, benchmark_description, dataset_ids],
            outputs=[process_status, preview_out_html, plan_out_md, plan_out_raw, code_out, eval_output_html],
            show_progress="hidden"
        )

        load_model_btn.click(_warmup_model, outputs=[]).then(get_status_text, outputs=[status_html])
        demo.load(_warmup_model, outputs=[]).then(get_status_text, outputs=[status_html])

    return demo
```

好的，针对您的需求，我进行了以下修改：

1.  **UI 交互完善**：在 "Suggested" 和 "Selected" 中间添加了 **"Add All"** 按钮。
2.  **视觉重点调整**：**Auto Search** 按钮现在使用了高亮的主色调（Primary Variant），并且调整了位置，使其更显眼。
3.  **字体与样式统一**：
    *   为 Suggested 和 Selected 表格应用了统一的 CSS 类，确保字体大小、内边距完全一致。
    *   Suggested 和 Selected 的标题现在采用了与 Benchmark Settings 类似的 Emerald 绿色调，视觉层级更清晰。
4.  **按钮美化**：重写了小操作按钮（Add, Delete等）的 CSS，去掉了默认的灰色背景，改为清爽的线框风格，鼠标悬停会有更细腻的反馈。

